import argparse
import json
import os
import numpy as np
import heapq
from collections import deque
from cogniplan_env import ExplorationEnv


def dijkstra(adj, start):
    N = len(adj)
    dist = [float('inf')] * N
    prev = [None] * N
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u] + 1e-9:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd + 1e-9 < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def round_coord(c):
    return tuple(np.round(np.array(c, dtype=float), 6))


def build_graph(nodes, robot_pos, neighbors):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord_to_idx[round_coord(n["coords"])] = i
    N = len(nodes)
    adj = [[] for _ in range(N)]
    for i, n in enumerate(nodes):
        for nb in n.get("neighbors", []):
            j = None
            if isinstance(nb, dict):
                nb = nb.get("coords", nb)
            if isinstance(nb, (list, tuple, np.ndarray)):
                j = coord_to_idx.get(round_coord(nb))
            else:
                try:
                    j = int(nb)
                    if not (0 <= j < N):
                        j = None
                except (ValueError, TypeError):
                    j = None
            if j is not None and j != i:
                w = float(np.linalg.norm(
                    np.array(n["coords"], dtype=float) -
                    np.array(nodes[j]["coords"], dtype=float)
                ))
                if w > 0:
                    adj[i].append((j, w))
    r_idx = N
    adj.append([])
    for nb in neighbors:
        j = coord_to_idx.get(round_coord(nb))
        if j is None:
            continue
        w = float(np.linalg.norm(
            np.array(robot_pos, dtype=float) -
            np.array(nb, dtype=float)
        ))
        if w > 0:
            adj[r_idx].append((j, w))
            adj[j].append((r_idx, w))
    return adj, coord_to_idx, r_idx


class GreedyPlanner:
    def __init__(self, dist_denom=3.6, reverse_penalty=0.3,
                 visited_penalty=0.1, persist_boost=1.05):
        self.dist_denom = dist_denom
        self.reverse_penalty = reverse_penalty
        self.visited_penalty = visited_penalty
        self.persist_boost = persist_boost
        self.reset()

    def reset(self):
        self.step_count = 0
        self.prev_pos = None
        self.last_target_j = None
        self.history = deque(maxlen=30)

    def plan(self, obs):
        self.step_count += 1
        robot_pos = np.array(obs["robot_pos"], dtype=float)
        nodes = obs["nodes"]
        neighbors = obs["neighbors"]
        frontiers = obs.get("frontiers", [])

        if not neighbors:
            self.prev_pos = robot_pos
            self.history.append(tuple(robot_pos))
            return None

        adj, coord_to_idx, r_idx = build_graph(nodes, robot_pos, neighbors)
        dist, prev = dijkstra(adj, r_idx)
        N = len(nodes)

        node_to_nb = {}
        for idx, nb in enumerate(neighbors):
            j = coord_to_idx.get(round_coord(nb))
            if j is not None:
                node_to_nb[j] = idx

        first_step = {}
        for j in range(N):
            if dist[j] == float('inf') or prev[j] is None:
                continue
            cur = j
            depth = 0
            while prev[cur] != r_idx and prev[cur] is not None and depth < N + 5:
                cur = prev[cur]
                depth += 1
            if prev[cur] == r_idx and cur in node_to_nb:
                first_step[j] = node_to_nb[cur]

        reverse_idx = None
        if self.prev_pos is not None:
            prev_vec = robot_pos - np.array(self.prev_pos, dtype=float)
            prev_norm = np.linalg.norm(prev_vec)
            if prev_norm > 0.01:
                best_dot = float('inf')
                for idx, nb in enumerate(neighbors):
                    nb_vec = np.array(nb, dtype=float) - robot_pos
                    dot = np.dot(prev_vec, nb_vec)
                    if dot < best_dot:
                        best_dot = dot
                        reverse_idx = idx

        best_score = -float('inf')
        best_j = None

        for j in range(N):
            if j not in first_step:
                continue
            utility = float(nodes[j].get("utility", 0.0))
            if utility <= 0:
                continue
            d = dist[j]
            score = utility / (d + self.dist_denom)
            if first_step[j] == reverse_idx:
                score *= self.reverse_penalty
            if nodes[j].get("visited", False):
                score *= (1.0 - self.visited_penalty)
            if j == self.last_target_j:
                score *= self.persist_boost
            if score > best_score:
                best_score = score
                best_j = j

        if best_j is not None:
            self.last_target_j = best_j
            target = neighbors[first_step[best_j]]
            self.prev_pos = robot_pos
            self.history.append(tuple(robot_pos))
            return target

        # Fallback 1: move toward nearest frontier
        if frontiers:
            best_score = -float('inf')
            best_nb = None
            for idx, nb in enumerate(neighbors):
                nb_arr = np.array(nb, dtype=float)
                min_d = min(np.linalg.norm(np.array(f, dtype=float) - nb_arr) for f in frontiers)
                score = 1.0 / (min_d + 1.0)
                if idx == reverse_idx:
                    score *= (1.0 - self.reverse_penalty)
                if score > best_score:
                    best_score = score
                    best_nb = nb
            if best_nb is not None:
                self.prev_pos = robot_pos
                self.history.append(tuple(robot_pos))
                return best_nb

        # Fallback 2: move toward nearest unvisited node
        best_score = -float('inf')
        best_nb = None
        for j in range(N):
            if nodes[j].get("visited", False):
                continue
            if j not in first_step:
                continue
            d = dist[j]
            score = 1.0 / (d + 1.0)
            fs = first_step[j]
            if fs == reverse_idx:
                score *= (1.0 - self.reverse_penalty)
            if score > best_score:
                best_score = score
                best_nb = neighbors[fs]
        if best_nb is not None:
            self.prev_pos = robot_pos
            self.history.append(tuple(robot_pos))
            return best_nb

        # Fallback 3: avoid recent history / reversing
        best_score = -float('inf')
        best_nb = None
        for idx, nb in enumerate(neighbors):
            score = 0.0
            nb_arr = np.array(nb, dtype=float)
            for h in self.history:
                score -= 1.0 / (np.linalg.norm(nb_arr - np.array(h, dtype=float)) + 0.1)
            if idx == reverse_idx:
                score -= 1.0
            if score > best_score:
                best_score = score
                best_nb = nb
        if best_nb is not None:
            self.prev_pos = robot_pos
            self.history.append(tuple(robot_pos))
            return best_nb

        self.prev_pos = robot_pos
        self.history.append(tuple(robot_pos))
        return neighbors[0] if neighbors else None


def run_episode(env, planner):
    obs = env.reset()
    planner.reset()
    for step in range(128):
        target = planner.plan(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info.get("done"):
            break
    return env.get_metrics()


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", required=True)
    parser.add_argument("--checkpoint", required=True)
    parser.add_argument("--output", required=True)
    args = parser.parse_args()

    ckpt_dir = args.checkpoint
    cfg_path = os.path.join(ckpt_dir, "planner_cfg.json")
    cfg = {}
    if os.path.exists(cfg_path):
        with open(cfg_path) as f:
            cfg = json.load(f)

    planner = GreedyPlanner(
        dist_denom=cfg.get("dist_denom", 2.0),
        reverse_penalty=cfg.get("reverse_penalty", 0.3),
        visited_penalty=cfg.get("visited_penalty", 0.1),
        persist_boost=cfg.get("persist_boost", 1.05),
    )

    data_path = args.data_path
    eval_config_path = os.path.join(data_path, "eval_config.json")
    maps_dir = os.path.join(data_path, "maps_eval")

    episodes = []
    if os.path.exists(eval_config_path):
        with open(eval_config_path) as f:
            eval_cfg = json.load(f)
        if isinstance(eval_cfg, list):
            episodes = eval_cfg
        elif isinstance(eval_cfg, dict):
            if "episodes" in eval_cfg:
                episodes = eval_cfg["episodes"]
            elif "maps" in eval_cfg:
                episodes = eval_cfg["maps"]

    if not episodes:
        for env_type in ["room", "tunnel", "outdoor"]:
            d = os.path.join(maps_dir, env_type)
            if not os.path.isdir(d):
                continue
            for fname in sorted(os.listdir(d)):
                if fname.endswith(".png"):
                    episodes.append({
                        "map_path": os.path.join("maps_eval", env_type, fname),
                        "env_type": env_type
                    })

    per_episode = []
    per_type = {t: {"explored_rate": [], "travel_distance": [], "success": []}
                for t in ["room", "tunnel", "outdoor"]}

    for ep in episodes:
        map_path = os.path.join(data_path, ep["map_path"])
        env_type = ep.get("env_type", "unknown")
        env = ExplorationEnv(map_path=map_path)
        metrics = run_episode(env, planner)
        success = 1 if metrics.get("success", False) else 0
        distance = float(metrics.get("travel_distance", 0.0))
        explored = float(metrics.get("explored_rate", 0.0))
        per_episode.append({
            "map_path": ep["map_path"],
            "env_type": env_type,
            "success": success,
            "travel_distance": distance,
            "explored_rate": explored
        })
        if env_type in per_type:
            per_type[env_type]["explored_rate"].append(explored)
            per_type[env_type]["travel_distance"].append(distance)
            per_type[env_type]["success"].append(success)

    total = len(per_episode)
    avg_explored = sum(e["explored_rate"] for e in per_episode) / total if total else 0.0
    success_rate = sum(e["success"] for e in per_episode) / total if total else 0.0
    successful_distances = [e["travel_distance"] for e in per_episode if e["success"] == 1]
    avg_distance = sum(successful_distances) / len(successful_distances) if successful_distances else 0.0

    per_type_out = {}
    for t, vals in per_type.items():
        n = len(vals["success"])
        if n == 0:
            continue
        s_dists = [d for d, s in zip(vals["travel_distance"], vals["success"]) if s == 1]
        per_type_out[t] = {
            "explored_rate": sum(vals["explored_rate"]) / n,
            "travel_distance": sum(s_dists) / len(s_dists) if s_dists else 0.0,
            "success_rate": sum(vals["success"]) / n
        }

    result = {
        "explored_rate": avg_explored,
        "travel_distance": avg_distance,
        "success_rate": success_rate,
        "per_episode": per_episode,
        "per_type": per_type_out,
        "total_episodes": total
    }

    with open(args.output, "w") as f:
        json.dump(result, f, indent=2)


if __name__ == "__main__":
    main()
